37	    return {
38	      state: state ? { status: state.status, risk_summary: state.risk_summary || state.riskSummary } : null,
39	      owners: tasks.map((t) => t.owner_group || t.ownerGroup),
40	      ownerTaskCount: tasks.length,
41	      customerMessage: msg?.body || "",
42	      auditVisible: audit.some((a) => a.customer_visible || a.customerVisible)
43	    };
